import React, { useState, useEffect } from 'react';
import { useSelector } from 'react-redux';
import { toast } from 'react-toastify';
import Modal from 'react-modal';

function AdminPanel() {
  const user = useSelector((state) => state.auth.user);
  const [users, setUsers] = useState([]);
  const [modalIsOpen, setModalIsOpen] = useState(false);
  const [modalAction, setModalAction] = useState({ type: '', id: null, role: '' });
  const [selectedUser, setSelectedUser] = useState(null);

  useEffect(() => {
    if (user?.role === "admin") {
      fetchUsers();
    }
  }, [user]);

  const fetchUsers = () => {
    fetch("http://localhost:3001/users")
      .then((res) => res.json())
      .then((data) => {
        const usersArray = Array.isArray(data) ? data : [];
        setUsers(usersArray);
      })
      .catch((error) => {
        console.error("Users fetch error:", error);
        toast.error("Ошибка загрузки пользователей");
      });
  };

  const openModal = (type, id, user) => {
    setModalAction({ type, id, role: user?.role || '' });
    setSelectedUser(user);
    setModalIsOpen(true);
  };

  const closeModal = () => {
    setModalIsOpen(false);
    setModalAction({ type: '', id: null, role: '' });
    setSelectedUser(null);
  };

  const handleRoleChange = async () => {
    if (modalAction.type === 'changeRole' && modalAction.id && selectedUser) {
      const adminCount = users.filter(u => u.role === "admin").length;
      if (modalAction.role === "admin" && adminCount >= 2) {
        toast.error("Максимум 2 администратора!");
        closeModal();
        return;
      }
      try {
        const response = await fetch(`http://localhost:3001/users/${modalAction.id}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ role: modalAction.role }),
        });
        if (response.ok) {
          toast.success('Роль изменена!');
          fetchUsers();
        } else {
          toast.error('Ошибка изменения роли');
        }
      } catch (error) {
        console.error('Role change error:', error);
        toast.error('Сетевая ошибка при изменении роли');
      }
    }
    closeModal();
  };

  const handleBan = async () => {
    if (modalAction.type === 'banUser' && modalAction.id) {
      try {
        const response = await fetch(`http://localhost:3001/users/${modalAction.id}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ banned: true }),
        });
        if (response.ok) {
          toast.success('Пользователь забанен!');
          fetchUsers();
        } else {
          toast.error('Ошибка бана пользователя');
        }
      } catch (error) {
        console.error('Ban user error:', error);
        toast.error('Сетевая ошибка при бане');
      }
    }
    closeModal();
  };

  if (user?.role !== "admin") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">Панель администратора</h1>
      <div className="card shadow">
        <div className="card-body">
          <h2>Пользователи</h2>
          <ul className="list-group">
            {users.map((u) => (
              <li key={u.id} className="list-group-item">
                {u.username} (Роль: {u.role}, Класс: {u.classId || 'Нет'}, Бан: {u.banned ? 'Да' : 'Нет'})
                <button
                  className="btn btn-warning btn-sm ms-2"
                  onClick={() => openModal('changeRole', u.id, u)}
                  disabled={u.role === "admin" && users.filter(au => au.role === "admin").length <= 2}
                >
                  Изменить роль
                </button>
                <button
                  className="btn btn-danger btn-sm ms-2"
                  onClick={() => openModal('banUser', u.id, u)}
                  disabled={u.banned}
                >
                  Забанить
                </button>
              </li>
            ))}
          </ul>
        </div>
      </div>
      <Modal
        isOpen={modalIsOpen}
        onRequestClose={closeModal}
        style={{
          content: {
            top: '50%',
            left: '50%',
            right: 'auto',
            bottom: 'auto',
            marginRight: '-50%',
            transform: 'translate(-50%, -50%)',
            width: '300px',
          },
        }}
      >
        <h2>{modalAction.type === 'changeRole' ? 'Изменение роли' : 'Бан пользователя'}</h2>
        {modalAction.type === 'changeRole' && (
          <>
            <p>Выберите новую роль для {selectedUser?.username}:</p>
            <select
              className="form-select mb-3"
              value={modalAction.role}
              onChange={(e) => setModalAction({ ...modalAction, role: e.target.value })}
            >
              <option value="student">Студент</option>
              <option value="teacher">Учитель</option>
              <option value="admin">Админ</option>
            </select>
            <button className="btn btn-primary" onClick={handleRoleChange}>Сохранить</button>
          </>
        )}
        {modalAction.type === 'banUser' && (
          <p>Забанить пользователя {selectedUser?.username}?</p>
        )}
        {modalAction.type === 'banUser' && (
          <button className="btn btn-danger" onClick={handleBan}>Да</button>
        )}
        <button className="btn btn-secondary ms-2" onClick={closeModal}>Нет</button>
      </Modal>
    </div>
  );
}

export default AdminPanel;
